import React, { useEffect, useState } from 'react';
import { useParams, Link } from 'react-router-dom';
import { getAnalysisById } from '../services/resume';
import {
  ChartBarIcon,
  CheckCircleIcon,
  XCircleIcon,
  LightBulbIcon,
  ArrowPathIcon
} from '@heroicons/react/24/outline';

const Result = () => {
  const { id } = useParams();
  const [analysis, setAnalysis] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadAnalysis();
  }, [id]);

  const loadAnalysis = async () => {
    try {
      const data = await getAnalysisById(id);
      setAnalysis(data);
    } catch (error) {
      console.error('Failed to load analysis:', error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <ArrowPathIcon className="h-8 w-8 text-indigo-600 animate-spin" />
      </div>
    );
  }

  if (!analysis) {
    return (
      <div className="text-center py-12">
        <p className="text-gray-500">Analysis not found</p>
        <Link to="/" className="btn-primary mt-4 inline-flex">
          Go to Dashboard
        </Link>
      </div>
    );
  }

  const getScoreColor = (score) => {
    if (score >= 80) return 'text-green-600';
    if (score >= 60) return 'text-yellow-600';
    return 'text-red-600';
  };

  const getProgressColor = (score) => {
    if (score >= 80) return 'bg-green-600';
    if (score >= 60) return 'bg-yellow-600';
    return 'bg-red-600';
  };

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      <div className="mb-8">
        <h1 className="text-2xl font-bold text-gray-900">Analysis Result</h1>
        <p className="text-gray-600">Here's how you stack up against the role.</p>
      </div>

      {/* Score Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
        <div className="card">
          <div className="flex items-center justify-between mb-4">
            <h3 className="text-lg font-semibold text-gray-900">ATS Score</h3>
            <ChartBarIcon className="h-6 w-6 text-gray-400" />
          </div>
          <div className="relative pt-1">
            <div className="flex mb-2 items-center justify-between">
              <div>
                <span className="text-xs font-semibold inline-block py-1 px-2 uppercase rounded-full text-indigo-600 bg-indigo-200">
                  Overall Resume Optimization
                </span>
              </div>
              <div className="text-right">
                <span className={`text-2xl font-bold ${getScoreColor(analysis.atsScore)}`}>
                  {analysis.atsScore}%
                </span>
              </div>
            </div>
            <div className="overflow-hidden h-2 mb-4 text-xs flex rounded bg-gray-200">
              <div
                style={{ width: `${analysis.atsScore}%` }}
                className={`shadow-none flex flex-col text-center whitespace-nowrap text-white justify-center ${getProgressColor(analysis.atsScore)}`}
              />
            </div>
          </div>
        </div>

        <div className="card">
          <div className="flex items-center justify-between mb-4">
            <h3 className="text-lg font-semibold text-gray-900">Skills Match</h3>
            <CheckCircleIcon className="h-6 w-6 text-gray-400" />
          </div>
          <div className="relative pt-1">
            <div className="flex mb-2 items-center justify-between">
              <div>
                <span className="text-xs font-semibold inline-block py-1 px-2 uppercase rounded-full text-green-600 bg-green-200">
                  Alignment with Job Requirements
                </span>
              </div>
              <div className="text-right">
                <span className={`text-2xl font-bold ${getScoreColor(analysis.matchPercentage)}`}>
                  {analysis.matchPercentage}%
                </span>
              </div>
            </div>
            <div className="overflow-hidden h-2 mb-4 text-xs flex rounded bg-gray-200">
              <div
                style={{ width: `${analysis.matchPercentage}%` }}
                className={`shadow-none flex flex-col text-center whitespace-nowrap text-white justify-center ${getProgressColor(analysis.matchPercentage)}`}
              />
            </div>
          </div>
        </div>
      </div>

      {/* Skills Section */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
        <div className="card">
          <h3 className="text-lg font-semibold text-gray-900 mb-4 flex items-center">
            <CheckCircleIcon className="h-5 w-5 text-green-500 mr-2" />
            Skills Found ({analysis.foundSkills?.length || 0})
          </h3>
          <div className="flex flex-wrap gap-2">
            {analysis.foundSkills?.map((skill, index) => (
              <span
                key={index}
                className="px-3 py-1 bg-green-100 text-green-800 rounded-full text-sm font-medium"
              >
                {skill}
              </span>
            ))}
          </div>
        </div>

        <div className="card">
          <h3 className="text-lg font-semibold text-gray-900 mb-4 flex items-center">
            <XCircleIcon className="h-5 w-5 text-red-500 mr-2" />
            Missing Skills ({analysis.missingSkills?.length || 0})
          </h3>
          <div className="flex flex-wrap gap-2">
            {analysis.missingSkills?.map((skill, index) => (
              <span
                key={index}
                className="px-3 py-1 bg-red-100 text-red-800 rounded-full text-sm font-medium"
              >
                {skill}
              </span>
            ))}
          </div>
        </div>
      </div>

      {/* Suggestions */}
      <div className="card mb-8">
        <h3 className="text-lg font-semibold text-gray-900 mb-4 flex items-center">
          <LightBulbIcon className="h-5 w-5 text-yellow-500 mr-2" />
          Improvement Suggestions ({analysis.suggestions?.length || 0})
        </h3>
        <ul className="space-y-3">
          {analysis.suggestions?.map((suggestion, index) => (
            <li key={index} className="flex items-start">
              <span className="inline-block w-5 h-5 bg-indigo-100 text-indigo-800 rounded-full text-xs font-medium flex items-center justify-center mr-3 mt-0.5">
                {index + 1}
              </span>
              <span className="text-gray-700">{suggestion}</span>
            </li>
          ))}
        </ul>
      </div>

      {/* Quick Stats */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="card text-center">
          <p className="text-sm text-gray-500">Found Skills</p>
          <p className="text-3xl font-bold text-gray-900">{analysis.foundSkills?.length || 0}</p>
        </div>
        <div className="card text-center">
          <p className="text-sm text-gray-500">Missing Skills</p>
          <p className="text-3xl font-bold text-gray-900">{analysis.missingSkills?.length || 0}</p>
        </div>
        <div className="card text-center">
          <p className="text-sm text-gray-500">Suggestions</p>
          <p className="text-3xl font-bold text-gray-900">{analysis.suggestions?.length || 0}</p>
        </div>
      </div>

      <div className="mt-8 text-center">
        <Link to="/analyze" className="btn-primary">
          New Analysis
        </Link>
      </div>
    </div>
  );
};

export default Result;
